def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    result = string
    for i in string:
        if i.islower():
            result = result.replace(i,i.upper(),1)
        elif i.isupper():
            result = result.replace(i, i.lower(), 1)
