    >>> flip_case('Hello')
    'hELLO'
    """
    result = string
    for i in range(len(string)):
        if string[i].islower():
            result = result[:i] + result[i].upper() + result[i + 1:]
        elif string[i].isupper():
            result = result[:i] + result[i].lower() + result[i + 1:]
    return result

def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    result = string
    for i in string:
        if i.islower():
            result = result.replace(i,i.upper(),1)
        elif i.isupper():
            result = result.replace(i, i.lower(), 1)
    return result

def unique(l: list):
    """Return sorted unique elements in a list
    >>> unique([5, 3, 5, 2, 3, 3, 9, 0, 123])
    [0, 2, 3, 5, 9, 123]
    """
    if isinstance(l, list):
        new = list()
        for i in l:
            if i not in new:
                new.append(i)
        new.sort()
        return new
    else:
        raise TypeError("Input must be of type 'list'.")

